import express from 'express';
import rateLimit from 'express-rate-limit';
import rateLimitHeader from 'rate-limit-header';

const app = express();

// Set up rate limiter
const limiter = rateLimit({
  windowMs: 60 * 1000,
  max: 10
});

// Apply rate limiter to all routes
app.use(limiter);

// Example route
app.get('/api/endpoint', (req, res) => {
  res.json({ message: 'OK' });
});

export default app;

