class Solution:
    def __init__(self):
        pass

    def solve(self):
        self.app = express()
        self.limiter = rateLimit({
            'windowMs': 60 * 1000,
            'max': 10
        })
        self.app.use('/api/', self.limiter)
        self.app.get('/api/endpoint', (req, res):
            res.json({"message": "OK"})
        )
